3	// Order summary query — reads from orders, accounts, invoices, shipments JSONB docs.
4	
5	export async function getOrderSummary(client, orderId) {
6		await ensureSchema(client);
7		const orderRes = await client.query('SELECT doc FROM orders WHERE order_id = $1', [orderId]);
8		if (!orderRes.rows[0]) return null;
9		const order = orderRes.rows[0].doc;
10		const acctRes = await client.query('SELECT doc FROM accounts WHERE account_id = $1', [order.accountId]);
11		const account = acctRes.rows[0]?.doc;
12		const invRes = await client.query("SELECT doc FROM invoices WHERE doc->>'orderId' = $1", [orderId]);
13		const invoice = invRes.rows[0]?.doc;
14		const shipRes = await client.query("SELECT doc FROM shipments WHERE doc->>'orderId' = $1", [orderId]);
15		const shipment = shipRes.rows[0]?.doc;
16		return {
17			orderId: order.orderId,
18			status: order.status,
19			totalCents: order.totalCents,
20			currency: order.currency,
21			lineItems: order.lineItems || [],
22			accountName: account?.name,
23			accountTier: account?.tier,
24			invoiceStatus: invoice?.status,
25			invoiceAmountCents: invoice?.amountCents,
26			shipmentStatus: shipment?.status,
27			carrier: shipment?.carrier,
28		};
29	}
